import java.io.IOException;
import java.util.Scanner;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a directory name: ");
        String directoryName = scanner.nextLine();

        // Validate input to prevent command injection
        if (!directoryName.matches("[a-zA-Z0-9_./]+")) {
            System.out.println("Invalid directory name. Please try again.");
            return;
        }

        try {
            ProcessBuilder processBuilder = new ProcessBuilder("ls", directoryName);
            Process process = processBuilder.start();

            // Do something with the process output
        } catch (IOException e) {
            e.printStackTrace();
        }

        scanner.close();
    }
}

